BEGIN;

-- acid-base: ab-stew-osm
UPDATE decision_nodes SET body = E'**Osmolar Gap = Measured Osm − Calculated Osm**\n\nCalculated Osm = 2×Na + Glucose/18 + BUN/2.8 + EtOH/3.7\n\n(Include EtOH term only if ethanol level is available — unmeasured ethanol falsely elevates the gap.)\n\n**Interpretation:**\n• **Gap ≤ 10:** Normal. Unmeasured anions are endogenous (uremia, ketoacids).\n• **Gap 10-50:** Elevated. Consider methanol, ethylene glycol, propylene glycol (lorazepam/diazepam/phenytoin infusions), isopropanol, mannitol, lithium.\n• **Gap > 50:** Almost certainly toxic alcohol ingestion.', recommendation = E'For suspected toxic alcohol: [Fomepizole](#/drug/fomepizole/toxic alcohol) 15 mg/kg IV loading dose. Consult toxicology and nephrology. Dialysis indicated for methanol/ethylene glycol with end-organ damage, severe acidosis, or renal failure.' WHERE id = 'ab-stew-osm' AND tree_id = 'acid-base';

-- delirium: del-correct-reversible
UPDATE decision_nodes SET body = E'Treat the identified cause with standard emergency care:\n\n• **Hypoglycemia:** D50W 25g IV (adults) or D10W 2-5 mL/kg (peds). Recheck glucose in 15 min.\n• **Hypoxia:** Supplemental O2 to SpO2 >94%. Evaluate for pneumonia, PE, CHF.\n• **Opioid toxicity:** [Naloxone](#/drug/naloxone/opioid toxicity) 0.4-2 mg IV/IN. May repeat q2-3 min. Consider infusion if recurrent (2/3 of effective dose per hour).\n• **Hypothermia:** Active warming. Evaluate for underlying cause.\n• **Hypotension:** IV fluid bolus. Evaluate for sepsis, hemorrhage, cardiac cause.\n\nIf mental status does not improve after correction, proceed with full delirium evaluation — multiple precipitants often coexist.' WHERE id = 'del-correct-reversible' AND tree_id = 'delirium';

-- distal-radius: dr-proc-sed
UPDATE decision_nodes SET body = E'**Procedural sedation** provides excellent analgesia and amnesia but requires more resources and time.\n\n**COMMON AGENTS:**\n• [Ketamine](#/drug/ketamine/procedural sedation) 1–2 mg/kg IV — dissociative, maintains airway reflexes\n• [Propofol](#/drug/propofol/procedural sedation) 0.5–1 mg/kg IV — rapid onset/offset, no analgesia (add fentanyl)\n• [Etomidate](#/drug/etomidate/procedural sedation) 0.1–0.15 mg/kg IV — hemodynamically stable\n\n**REQUIREMENTS:**\n• NPO assessment (ideally 2+ hours for clear liquids)\n• Dedicated monitoring nurse\n• Capnography, pulse oximetry, cardiac monitor\n• Resuscitation equipment at bedside\n• Longer ED stay (mean 4.6 hours vs 1.5 hours for hematoma block) [4]\n\n**BEST FOR:** Complex reductions, highly anxious patients, pediatric patients who cannot cooperate with hematoma block.' WHERE id = 'dr-proc-sed' AND tree_id = 'distal-radius';

COMMIT;